#!/bin/bash
mask=$(( $2 == 0 ? 0 : 0xffffffff << (32 - $2) )); IFS=. read -r i1 i2 i3 i4 <<< "$1"; ip=$(( (i1 << 24) | (i2 << 16) | (i3 << 8) | i4 )); net=$(( ip & mask )); bc=$(( net | (0xffffffff ^ mask) )); f=$(( net + 1 )); l=$(( bc - 1 )); printf "%d.%d.%d.%d - %d.%d.%d.%d" $(( (f >> 24) & 255 )) $(( (f >> 16) & 255 )) $(( (f >> 8) & 255 )) $(( f & 255 )) $(( (l >> 24) & 255 )) $(( (l >> 16) & 255 )) $(( (l >> 8) & 255 )) $(( l & 255 )) | tr -d "\n"
